tElementById("popup-overlay"); popupImage = popupOverlay.querySelector(".popup-image"); // Initialize GSAP plugins const { gsap } = window; // Check if GSAP plugins are available before using them if (gsap) { if (gsap.registerPlugin) { if (window.Flip) gsap.registerPlugin(window.Flip); if (window.ScrollTrigger) gsap.registerPlugin(window.ScrollTrigger); if (window.CustomEase) { gsap.registerPlugin(window.CustomEase); // Only create custom ease if the plugin is available window.CustomEase.create("customEase", "0.6, 0.01, 0.05, 1"); } } } // Initialize Lenis for smooth scrolling initLenis(); renderProjects(); attachHoverEvents(); setupGlobalEvents(); setupLogoAnimations(); setupFooterAnimation(); forceImageLoad(); initialAnimation(); toggleButtons.forEach((btn) => { btn.addEventListener("click", () => { const viewType = btn.dataset.view; toggleView(viewType); }); }); }); // Initialize Lenis smooth scrolling function initLenis() { // Initialize a new Lenis instance for smooth scrolling lenis = new Lenis({ duration: 1.2, easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)), // Exponential easing direction: "vertical", gestureDirection: "vertical", smooth: true, mouseMultiplier: 1, smoothTouch: false, touchMultiplier: 2, infinite: false }); // Synchronize Lenis scrolling with GSAP's ScrollTrigger plugin lenis.on("scroll", ScrollTrigger.update); // Add Lenis's requestAnimationFrame (raf) method to GSAP's ticker // This ensures Lenis's smooth scroll animation updates on each GSAP tick gsap.ticker.add((time) => { lenis.raf(time * 1000); // Convert time from seconds to milliseconds }); // Disable lag smoothing in GSAP to prevent any delay in scroll animations gsap.ticker.lagSmoothing(0); } // Setup header logo animation with clip-path function setupLogoAnimations() { const { gsap } = window; if (!gsap) return; // Prepare header logo paths for animation const headerLogoPaths = document.querySelectorAll(".header-logo .logo-path"); // Make the header logo container visible 